sc_cat_item_producer.script:
/** This script is executed before the Record is generated
* `current`- GlideRecord produced by Record Producer
* Don't use `current.update()` or `current.insert()` as the record is generated by Record Producer
* Don't use `current.setValue('sys_class_name', 'xxx')` as this will trigger reparent flow and can cause data loss
* Avoid `current.setAbortAction()` and generate a separate record
* Use `producer.var1` to access variables
*/
// Set the initial status to 'Submitted' automatically
current.application_status = 'submitted';


//This code auto populates the Academic Records

// Get the MRVS data.
var mrvsData = producer.academic_record;

// current.u_academic_record = JSON.parse(mrvsData);
// Log 1: Check what exact data is coming from the MRVS
// gs.info("AUMS Debug - Raw MRVS Data: " + mrvsData);

// Create an empty array to collect the references (Sys IDs)
var referenceList = [];

// Parse the JSON string into a JavaScript array
var parsedData = JSON.parse(mrvsData);

// 3. Loop through each row the applicant added
for (var i = 0; i < parsedData.length; i++) {

	// 4. Create a new record in your new Child Table
	var grAcademic = new GlideRecord('x_595775_automat_0_academic_record');
	grAcademic.initialize();

	// Link this academic record to the newly created Application record
	grAcademic.u_admission_application = current.sys_id;

	// Map the MRVS variables to the child table fields
	grAcademic.u_degree_level = parsedData[i].u_degree_level;
	grAcademic.u_institution_board = parsedData[i].u_institution_board;
	grAcademic.u_passing_year = parsedData[i].u_passing_year;
	grAcademic.u_roll_number = parsedData[i].u_roll_number;
	grAcademic.u_cgpa = parsedData[i].u_cgpa;
	grAcademic.u_total_marks = parsedData[i].u_total_marks;
	grAcademic.u_obtained_marks = parsedData[i].u_obtained_marks;

	// Insert the row into the database and capture the Sys ID
	var newSysId = grAcademic.insert();

	if (newSysId) {
        referenceList.push(newSysId);
    }
}

if (referenceList.length >= 0) {
    current.u_academic_record = referenceList.join(',');
}



// This code is for Assignment Group and Assigned to Auto population

// 1. Define the name of your assignment group
var targetGroupName = 'Admission Team'; // <-- Change this to your exact group name

// 2. Query the group table to get the Group's Sys ID
var groupSysId = '';
var groupGR = new GlideRecord('sys_user_group');
if (groupGR.get('name', targetGroupName)) {
    groupSysId = groupGR.getUniqueValue();

    // Set the target record's Assignment Group
    current.assignment_group = groupSysId;

    // 3. Query the Group Member table to find all active users in this group
    var groupMembers = [];
    var memberGR = new GlideRecord('sys_user_grmember');
    memberGR.addQuery('group', groupSysId);
    memberGR.addQuery('user.active', true); // Crucial: Only assign to active users
    memberGR.query();

    while (memberGR.next()) {
        groupMembers.push(memberGR.getValue('user'));
    }

    // 4. Randomly select one user from the array
    if (groupMembers.length > 0) {
        // Math.random() generates a decimal, which we multiply by the array length and round down
        var randomIndex = Math.floor(Math.random() * groupMembers.length);

        // Assign the ticket to the randomly selected user
        current.assigned_to = groupMembers[randomIndex];
    }
}
